SELECT DISTINCT ?name ?population WHERE {
  SERVICE <https://qlever.cs.uni-freiburg.de/api/wikidata> {
    ?city wdt:P31/wdt:P279* wd:Q515 .
    ?city wdt:P17 wd:Q183 .
    ?city wdt:P1082 ?population .
    ?city rdfs:label ?name .
    FILTER (LANG(?name) = "de")
  }
}
ORDER BY DESC(?population)

SELECT ?p ?count ?percent WHERE {
  { SELECT ?p (COUNT(?p) AS ?count) WHERE { ?s ?p ?o } GROUP BY ?p }
  BIND(100 * ?count / SUM(?count) AS ?percent)
}
ORDER BY DESC(?count)

SELECT ?p ?count (100 * ?count / ?count_all AS ?percent) WHERE {
  { SELECT ?p (COUNT(?p) AS ?count) WHERE { ?s ?p ?o } GROUP BY ?p }
  { SELECT (COUNT(?s) AS ?count_all) WHERE { ?s ?p ?o } }
}
ORDER BY DESC(?count)

